import{_ as e,o as i,c as s,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Capas y reglas de dependencia","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/02-capas-y-reglas-de-dependencia.md","filePath":"full-stack/arquitectura/clean-architecture/02-capas-y-reglas-de-dependencia.md","lastUpdated":1782521464000}'),l={name:"full-stack/arquitectura/clean-architecture/02-capas-y-reglas-de-dependencia.md"};function t(o,a,r,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="capas-y-reglas-de-dependencia" tabindex="-1">Capas y reglas de dependencia <a class="header-anchor" href="#capas-y-reglas-de-dependencia" aria-label="Permalink to &quot;Capas y reglas de dependencia&quot;">​</a></h1><p>La arquitectura limpia separa el sistema por responsabilidad. Cada capa tiene un motivo distinto para cambiar y una relacion clara con las demas.</p><h2 id="capas-habituales" tabindex="-1">Capas habituales <a class="header-anchor" href="#capas-habituales" aria-label="Permalink to &quot;Capas habituales&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>  domain/</span></span>
<span class="line"><span>  application/</span></span>
<span class="line"><span>  infrastructure/</span></span>
<span class="line"><span>  presentation/</span></span></code></pre></div><h2 id="domain" tabindex="-1">Domain <a class="header-anchor" href="#domain" aria-label="Permalink to &quot;Domain&quot;">​</a></h2><p>Contiene reglas de negocio puras:</p><ul><li>Entidades.</li><li>Value objects.</li><li>Reglas invariantes.</li><li>Errores del dominio.</li><li>Servicios de dominio cuando una regla no pertenece a una sola entidad.</li></ul><p>No debe importar frameworks, ORM, HTTP, colas, logs ni librerias de UI.</p><h2 id="application" tabindex="-1">Application <a class="header-anchor" href="#application" aria-label="Permalink to &quot;Application&quot;">​</a></h2><p>Contiene casos de uso. Coordina una intencion del sistema:</p><ul><li>Crear un pedido.</li><li>Publicar un articulo.</li><li>Registrar un usuario.</li><li>Calcular una factura.</li><li>Procesar un pago.</li></ul><p>Puede depender del dominio y de puertos abstractos, pero no de adaptadores concretos.</p><h2 id="infrastructure" tabindex="-1">Infrastructure <a class="header-anchor" href="#infrastructure" aria-label="Permalink to &quot;Infrastructure&quot;">​</a></h2><p>Contiene detalles tecnicos:</p><ul><li>Repositorios SQL.</li><li>Clientes HTTP.</li><li>Productores Kafka.</li><li>Lectores de archivos.</li><li>Servicios de email.</li><li>Adaptadores de cache.</li></ul><p>Esta capa cambia cuando cambia la tecnologia.</p><h2 id="presentation" tabindex="-1">Presentation <a class="header-anchor" href="#presentation" aria-label="Permalink to &quot;Presentation&quot;">​</a></h2><p>Es la entrada al sistema:</p><ul><li>Controladores REST.</li><li>GraphQL resolvers.</li><li>CLI commands.</li><li>Jobs programados.</li><li>Consumers de eventos.</li></ul><p>Su trabajo es traducir entrada externa a comandos internos y devolver respuestas entendibles.</p><h2 id="regla-de-dependencia" tabindex="-1">Regla de dependencia <a class="header-anchor" href="#regla-de-dependencia" aria-label="Permalink to &quot;Regla de dependencia&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>presentation -&gt; application -&gt; domain</span></span>
<span class="line"><span>infrastructure -&gt; application -&gt; domain</span></span></code></pre></div><p>El dominio no apunta a nadie. La aplicacion no debe conocer controladores, ORM ni frameworks web. La infraestructura implementa contratos definidos por la aplicacion o por el dominio.</p><h2 id="ejemplo-practico" tabindex="-1">Ejemplo practico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo practico&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /orders</span></span>
<span class="line"><span>  -&gt; OrderController</span></span>
<span class="line"><span>  -&gt; CreateOrderUseCase</span></span>
<span class="line"><span>  -&gt; OrderRepository</span></span>
<span class="line"><span>  -&gt; SqlOrderRepository</span></span></code></pre></div><p>El caso de uso sabe que necesita guardar un pedido. No sabe si el guardado ocurre en PostgreSQL, MongoDB, un archivo o un mock de test.</p><h2 id="senales-de-mala-dependencia" tabindex="-1">Senales de mala dependencia <a class="header-anchor" href="#senales-de-mala-dependencia" aria-label="Permalink to &quot;Senales de mala dependencia&quot;">​</a></h2><ul><li>Una entidad importa un modelo de ORM.</li><li>Un caso de uso recibe un objeto Request de Express, Django, Laravel o Spring.</li><li>Una regla de negocio lee variables de entorno directamente.</li><li>Un test de dominio necesita arrancar Docker.</li><li>Cambiar de proveedor de email obliga a tocar controladores y entidades.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Las dependencias del dominio son cero o casi cero.</li><li>Los casos de uso reciben datos simples o DTOs propios.</li><li>Los adaptadores se pueden sustituir sin tocar reglas de negocio.</li><li>Las interfaces estan cerca del caso de uso que las necesita.</li><li>La infraestructura se configura en el borde de la aplicacion.</li></ul>`,30)])])}const m=e(l,[["render",t]]);export{h as __pageData,m as default};
